SELECT *
FROM leave_records
WHERE start_date >= #{startDate} AND end_date <= #{endDate}

SELECT *
FROM leave_records
WHERE start_date >= #{startDate}
  AND end_date <= #{endDate}
  AND leave_type = #{leaveType}

SELECT SUM(hours)
FROM leave_records
WHERE employee_id = #{employeeId}
  AND leave_type = #{leaveType}
  AND status = 'APPROVED'
  AND leave_date BETWEEN #{startDate} AND #{endDate}

SELECT COUNT(*)
FROM leave_records
WHERE employee_id = #{employeeId}
  AND leave_type = #{leaveType}
  AND status = 'APPROVED'
  AND leave_date BETWEEN #{startDate} AND #{endDate}

SELECT *
FROM leave_records
WHERE employee_id = #{employeeId}
  AND DATE_FORMAT(leave_date, '%Y-%m') = #{month}

SELECT *
FROM leave_records
WHERE employee_id IN

    #{id}

  AND leave_date BETWEEN #{startDate} AND #{endDate}
